allow:
Bash("d:\\SaaS\\frontend-vite\\nginx.conf" << 'EOF'
# Nginx конфігурація для React SPA \(Single Page Application\)

server {
    listen 3000;
    server_name localhost;

    root /usr/share/nginx/html;
    index index.html;

    # Gzip compression для кращої продуктивності
    gzip on;
    gzip_vary on;
    gzip_min_length 1024;
    gzip_types
        text/plain
        text/css
        text/xml
        text/javascript
        application/javascript
        application/xml+rss
        application/json
        image/svg+xml;

    # Security headers
    add_header X-Frame-Options "SAMEORIGIN" always;
    add_header X-Content-Type-Options "nosniff" always;
    add_header X-XSS-Protection "1; mode=block" always;
    add_header Referrer-Policy "no-referrer-when-downgrade" always;

    # React Router - всі роути через index.html
    location / {
        try_files $uri $uri/ /index.html;
    }

    # Кешування статичних файлів \(JS, CSS, fonts, images\)
    location ~* \\.\(js|css|png|jpg|jpeg|gif|ico|svg|woff|woff2|ttf|eot\)$ {
        expires 1y;
        add_header Cache-Control "public, immutable";
        access_log off;
    }

    # Заборонити доступ до прихованих файлів
    location ~ /\\. {
        deny all;
        access_log off;
        log_not_found off;
    }

    # Health check endpoint
    location /health {
        access_log off;
        return 200 "OK\\n";
        add_header Content-Type text/plain;
    }

    # Логування
    access_log /var/log/nginx/access.log;
    error_log /var/log/nginx/error.log warn;
}
EOF)
